// BankServiceServer is the server API for BankService service.
// All implementations should embed UnimplementedBankServiceServer
// for forward compatibility.
//
// BankService owns the c2 banking entities: companies, accounts (and
// later cards, payments, transfers, exchange, loans). The slice 1
// surface here is companies + accounts (incl. system house accounts);
// payment/card/loan RPCs land in subsequent slices.
//
// Public REST surface: every RPC with a google.api.http annotation is
// exposed on the gateway at /api/v1/...
type BankServiceServer interface {
	CreateCompany(context.Context, *CreateCompanyRequest) (*Company, error)
	ListCompanies(context.Context, *ListCompaniesRequest) (*ListCompaniesResponse, error)
	GetCompany(context.Context, *GetCompanyRequest) (*Company, error)
	UpdateCompany(context.Context, *UpdateCompanyRequest) (*Company, error)
	CreateAccount(context.Context, *CreateAccountRequest) (*Account, error)
	ListAccounts(context.Context, *ListAccountsRequest) (*ListAccountsResponse, error)
	GetAccount(context.Context, *GetAccountRequest) (*Account, error)
	UpdateAccountLimits(context.Context, *UpdateAccountLimitsRequest) (*Account, error)
	// UpdateAccountName implements spec p.20 "Promena naziva računa".
	// Only the account owner may rename. The new name must differ from
	// the current name and must not collide with another active account
	// owned by the same client. No verification gate — renaming doesn't
	// move money, and the spec p.20 popup doesn't require a code (only
	// limit changes do).
	UpdateAccountName(context.Context, *UpdateAccountNameRequest) (*Account, error)
	SetAccountStatus(context.Context, *SetAccountStatusRequest) (*Account, error)
	// GetSystemAccount returns the bank's own house account for a given
	// currency. Used by exchange/payment code paths so all FX flows
	// through bank-owned accounts (spec edge case: every FX conversion
	// hops through the bank in RSD twice).
	GetSystemAccount(context.Context, *GetSystemAccountRequest) (*Account, error)
	// SettleTrade is the trading service's settlement primitive. Each
	// partial fill (spec p.55-56) calls this to move money between the
	// user's bank account and the bank's house account in the security's
	// listing currency. Same-currency = single leg; FX = two legs via
	// the menjačnica engine. Bank does no commission math here — the
	// caller has already net-bundled commission into `amount`.
	SettleTrade(context.Context, *SettleTradeRequest) (*SettleTradeResponse, error)
	// SettleCapitalGainsTax debits the user's trading account and credits
	// the state's RSD account by `amount_rsd` (spec p.62). The RPC takes
	// the RSD figure directly; bank inverts the menjačnica engine to
	// pull the matching source-currency amount from the user's account
	// (commission-free per spec p.62, regardless of actor type). Idempotent
	// on `op_id`. Internal RPC — no http annotation, callers authenticate
	// with admin metadata.
	SettleCapitalGainsTax(context.Context, *SettleCapitalGainsTaxRequest) (*SettleCapitalGainsTaxResponse, error)
	// SettleDividend credits `account_id` by `amount` (in `currency`,
	// the security's listing currency) sourced from the bank's
	// per-currency house account — the quarterly dividend payout (todoSpec
	// C3 S54-S59). When the destination account is in a different currency
	// the menjačnica engine converts commission-free so RSD-only holders
	// still get paid (S56). Idempotent on `op_id`. Internal RPC — no http
	// annotation, callers authenticate with admin metadata.
	SettleDividend(context.Context, *SettleDividendRequest) (*SettleDividendResponse, error)
	// SettleForexFill atomically settles the two paired cash legs of a
	// forex pair fill (spec p.42). Each leg moves the bank's per-currency
	// forex_book account against the per-currency menjačnica house. The
	// forex_book represents the bank's open FX positions and acts as the
	// conceptual "market" counterparty. Idempotent on `op_id`. Internal
	// RPC — no http annotation, callers authenticate with admin metadata.
	SettleForexFill(context.Context, *SettleForexFillRequest) (*SettleForexFillResponse, error)
	// ReserveFunds debits the source account's available_balance (leaving
	// balance untouched) and inserts a `held` reservation row. Used by
	// the c4 SAGA orchestrator as step 1 of OTC premium / OTC exercise /
	// fund-invest / fund-withdraw flows. Idempotent on op_id — a retry
	// returns the existing reservation rather than double-debiting.
	ReserveFunds(context.Context, *ReserveFundsRequest) (*ReserveFundsResponse, error)
	// ReleaseFunds re-credits available_balance and flips the reservation
	// row to `released`. Compensating step in every SAGA that calls
	// ReserveFunds. No-op (success) when the reservation is already
	// released or never existed — SAGA compensations need to be
	// idempotent and runnable out-of-order from the failed forward step.
	ReleaseFunds(context.Context, *ReleaseFundsRequest) (*ReleaseFundsResponse, error)
	// CommitReservedFunds finalises a held reservation: in one tx debits
	// `balance` on the source (available_balance already debited at
	// reserve time), credits the destination's balance + available_balance,
	// and flips the reservation row to `committed`. Cross-currency
	// commits hop through the bank's house accounts (same menjačnica
	// convention as SettleTrade). Idempotent on op_id.
	CommitReservedFunds(context.Context, *CommitReservedFundsRequest) (*CommitReservedFundsResponse, error)
	// TransferBetweenClients is the convenience wrapper composing
	// ReserveFunds + CommitReservedFunds when no FX hop is needed (or
	// when the caller wants the bank to handle the FX hop internally).
	// Used by OTC premium + OTC exercise + fund invest/withdraw whenever
	// both legs are in compatible currencies. `is_actuary` toggles the
	// FX commission off (spec p.55 actuary path); op_kind tags the
	// ledger leg so reporting (Profit Banke + pregled plaćanja) can
	// distinguish OTC vs fund flows.
	TransferBetweenClients(context.Context, *TransferBetweenClientsRequest) (*TransferBetweenClientsResponse, error)
	// CreateFundAccount mints a kind='fund' RSD account owned by the
	// FundsOwnerID sentinel. Trading service dials this internally at
	// CreateFund time. Distinct from CreateAccount so the client-facing
	// path can keep rejecting kind=fund as a validation error.
	CreateFundAccount(context.Context, *CreateFundAccountRequest) (*Account, error)
	CreatePayment(context.Context, *CreatePaymentRequest) (*PaymentResult, error)
	CreateTransfer(context.Context, *CreateTransferRequest) (*PaymentResult, error)
	// QuoteExchange returns the converted-amount preview for a
	// menjačnica or FX payment, including commission. The FE uses this
	// to render the transfer-confirmation screen before the user clicks
	// Potvrdi.
	QuoteExchange(context.Context, *QuoteExchangeRequest) (*QuoteExchangeResponse, error)
	ListTransactions(context.Context, *ListTransactionsRequest) (*ListTransactionsResponse, error)
	CreatePaymentRecipient(context.Context, *CreatePaymentRecipientRequest) (*PaymentRecipient, error)
	ListPaymentRecipients(context.Context, *ListPaymentRecipientsRequest) (*ListPaymentRecipientsResponse, error)
	UpdatePaymentRecipient(context.Context, *UpdatePaymentRecipientRequest) (*PaymentRecipient, error)
	DeletePaymentRecipient(context.Context, *DeletePaymentRecipientRequest) (*emptypb.Empty, error)
	SchedulePayment(context.Context, *SchedulePaymentRequest) (*ScheduledPayment, error)
	ListScheduledPayments(context.Context, *ListScheduledPaymentsRequest) (*ListScheduledPaymentsResponse, error)
	CancelScheduledPayment(context.Context, *CancelScheduledPaymentRequest) (*ScheduledPayment, error)
	// RunDueScheduledPayments attempts execution of every scheduled
	// payment whose date has arrived. Normally driven by the scheduler
	// service; admin-only. Internal — no http annotation.
	RunDueScheduledPayments(context.Context, *RunDueScheduledPaymentsRequest) (*RunDueScheduledPaymentsResponse, error)
	CreateCard(context.Context, *CreateCardRequest) (*Card, error)
	ListCards(context.Context, *ListCardsRequest) (*ListCardsResponse, error)
	SetCardStatus(context.Context, *SetCardStatusRequest) (*Card, error)
	// UpdateCardLimit changes a card's per-card spending limit (flow.pdf
	// P6 "Klijent menja limit kartice"). Verification-gated by the
	// gateway middleware — same policy as account-limit changes.
	UpdateCardLimit(context.Context, *UpdateCardLimitRequest) (*Card, error)
	CreateAuthorizedPerson(context.Context, *CreateAuthorizedPersonRequest) (*AuthorizedPerson, error)
	ListAuthorizedPersons(context.Context, *ListAuthorizedPersonsRequest) (*ListAuthorizedPersonsResponse, error)
	SubmitLoanRequest(context.Context, *SubmitLoanRequestRequest) (*LoanRequest, error)
	ListLoanRequests(context.Context, *ListLoanRequestsRequest) (*ListLoanRequestsResponse, error)
	DecideLoanRequest(context.Context, *DecideLoanRequestRequest) (*LoanRequest, error)
	ListLoans(context.Context, *ListLoansRequest) (*ListLoansResponse, error)
	GetLoan(context.Context, *GetLoanRequest) (*LoanWithInstallments, error)
	// RunInstallmentJob debits any installments that are due today.
	// Normally driven by the daily cron; exposed as an RPC so tests and
	// ops can fire it on demand. Admin-only.
	RunInstallmentJob(context.Context, *RunInstallmentJobRequest) (*RunInstallmentJobResponse, error)
	// RunVariableRateJob refreshes the random pomeraj for every active
	// variable-rate loan and recomputes its installment amount. Admin-only.
	RunVariableRateJob(context.Context, *RunVariableRateJobRequest) (*RunVariableRateJobResponse, error)
	// RunMaintenanceFeeJob debits the monthly maintenance fee from every
	// account due for it. Normally driven by the scheduler service; exposed
	// as an RPC so ops can fire it on demand. Admin-only.
	RunMaintenanceFeeJob(context.Context, *RunMaintenanceFeeJobRequest) (*RunMaintenanceFeeJobResponse, error)
	// RunSpentResetJob zeroes the daily/monthly spent counters that are due
	// to roll over. Normally driven by the scheduler service; admin-only.
	RunSpentResetJob(context.Context, *RunSpentResetJobRequest) (*RunSpentResetJobResponse, error)
	// QuoteForexForward returns a side-effect-free preview of a prospective
	// forward: the locked-in ForwardRate (= SpotAsk × (1 + days/365 ×
	// spread)) plus the reserved obligation amount and commission.
	QuoteForexForward(context.Context, *QuoteForexForwardRequest) (*ForexForwardQuote, error)
	// CreateForexForward concludes a forward: locks the rate, reserves the
	// RSD obligation on the client's RSD account, charges the commission,
	// and persists the contract as 'active'.
	CreateForexForward(context.Context, *CreateForexForwardRequest) (*ForexForward, error)
	// ListForexForwards returns the caller's forward contracts.
	ListForexForwards(context.Context, *ListForexForwardsRequest) (*ListForexForwardsResponse, error)
	// CancelForexForward cancels a still-'active' contract and releases the
	// reservation.
	CancelForexForward(context.Context, *CancelForexForwardRequest) (*ForexForward, error)
	// GetForexForwardSpreads returns every configured pair's SpreadFactor.
	GetForexForwardSpreads(context.Context, *GetForexForwardSpreadsRequest) (*GetForexForwardSpreadsResponse, error)
	// SetForexForwardSpread upserts a pair's SpreadFactor. Supervisor-only.
	SetForexForwardSpread(context.Context, *SetForexForwardSpreadRequest) (*ForexForwardSpread, error)
	// RunForexForwardSettlement settles every active forward whose
	// settlement date has arrived. Internal — driven by the scheduler.
	RunForexForwardSettlement(context.Context, *RunForexForwardSettlementRequest) (*RunForexForwardSettlementResponse, error)
}

